-- ── 대차차량 vehicle_id 연결 (cars.number 매칭) ──
UPDATE fmi_rentals r JOIN cars c ON c.`number` = r.vehicle_car_number
  SET r.vehicle_id = c.id
  WHERE r.fleet_group = '빌려타' AND r.vehicle_id IS NULL;

